#include <bits/stdc++.h>
using namespace std;
const int N=65;
int n,m,v[N][3],p[N][3],dp[32005],cnt;
int main()
{
    cin>>n>>m;
    for(int i=1;i<=m;i++)
    {
        int x,y,z;
        cin>>x>>y>>z;
        if(z==0)
        {
            v[i][0]=x;
            p[i][0]=y*x;
        }
        else
        {
            if(v[z][1])
            {
                v[z][2]=x;
                p[z][2]=y*x;
            }
            else
            {
                v[z][1]=x;
                p[z][1]=y*x;
            }
        }
    }
    for(int i=1;i<=m;i++)
    {
        for(int j=n;j>=v[i][0];j--)
        {
            dp[j]=max(dp[j],dp[j-v[i][0]]+p[i][0]);
            if(j>=v[i][0]+v[i][1]) dp[j]=max(dp[j],dp[j-v[i][0]-v[i][1]]+p[i][0]+p[i][1]);
            if(j>=v[i][0]+v[i][1]+v[i][2]) dp[j]=max(dp[j],dp[j-v[i][0]-v[i][1]-v[i][2]]+p[i][0]+p[i][1]+p[i][2]);
            if(j>=v[i][0]+v[i][2]) dp[j]=max(dp[j],dp[j-v[i][0]-v[i][2]]+p[i][0]+p[i][2]);
        }
    }
    cout<<dp[n];
    return 0;
}
